package hashring

import (
	"hash/crc32"
	"sort"
	"strconv"
	"sync"
)

type Ring struct {
	mu       sync.RWMutex
	replicas int            // virtual nodes per physical node
	keys     []uint32       // sorted ring positions
	hashMap  map[uint32]string
}

func New(replicas int) *Ring {
	return &Ring{replicas: replicas, hashMap: make(map[uint32]string)}
}

func (r *Ring) hash(s string) uint32 {
	return crc32.ChecksumIEEE([]byte(s))
}

// Add places `node` at `replicas` points on the ring.
func (r *Ring) Add(node string) {
	r.mu.Lock()
	defer r.mu.Unlock()
	for i := 0; i < r.replicas; i++ {
		h := r.hash(node + "#" + strconv.Itoa(i))
		r.keys = append(r.keys, h)
		r.hashMap[h] = node
	}
	sort.Slice(r.keys, func(i, j int) bool { return r.keys[i] < r.keys[j] })
}

// Remove deletes all virtual nodes for `node`.
func (r *Ring) Remove(node string) {
	r.mu.Lock()
	defer r.mu.Unlock()
	kept := r.keys[:0]
	for _, h := range r.keys {
		if r.hashMap[h] == node {
			delete(r.hashMap, h)
			continue
		}
		kept = append(kept, h)
	}
	r.keys = kept
}

// Get returns the node owning `key` (first vnode clockwise).
func (r *Ring) Get(key string) string {
	r.mu.RLock()
	defer r.mu.RUnlock()
	if len(r.keys) == 0 {
		return ""
	}
	h := r.hash(key)
	i := sort.Search(len(r.keys), func(i int) bool { return r.keys[i] >= h })
	if i == len(r.keys) {
		i = 0 // wrap around the ring
	}
	return r.hashMap[r.keys[i]]
}

// Retry with capped exponential backoff + full jitter (avoids synchronized retries)
func backoff(attempt int) time.Duration {
	const base, max = 50 * time.Millisecond, 2 * time.Second
	d := base << attempt          // 50ms, 100ms, 200ms, ...
	if d > max {
		d = max
	}
	return time.Duration(rand.Int63n(int64(d))) // FULL jitter: pick in [0, d)
}

// Retry budget: only retry if recent retry ratio is under the cap.
// budget.Allow() returns false once retries exceed e.g. 10% of requests,
// turning a retry storm back into a single failed request.
if err := call(); err != nil && idempotent && budget.Allow() {
	time.Sleep(backoff(attempt))
	err = call()
}

// Graceful shutdown: fail readiness first, drain in-flight, then exit.
func main() {
	srv := &http.Server{Addr: ":8443", Handler: mux}
	ready := atomic.Bool{}
	ready.Store(true)

	// /readyz returns 503 the instant we begin shutdown -> LB stops new traffic
	mux.HandleFunc("/readyz", func(w http.ResponseWriter, _ *http.Request) {
		if !ready.Load() {
			w.WriteHeader(http.StatusServiceUnavailable)
			return
		}
		w.WriteHeader(http.StatusOK)
	})

	go srv.ListenAndServeTLS(crt, key)

	stop := make(chan os.Signal, 1)
	signal.Notify(stop, syscall.SIGTERM)
	<-stop

	ready.Store(false)                 // 1. mark unready; LB drains us out
	time.Sleep(5 * time.Second)        // 2. let LB notice (health interval)

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()
	srv.Shutdown(ctx)                  // 3. finish in-flight, refuse new, then exit
}

