		h := hash(node + "#" + strconv.Itoa(i))
		r.keys = append(r.keys, h)
		r.hashMap[h] = node
	}
	sort.Slice(r.keys, func(i, j int) bool { return r.keys[i] < r.keys[j] })
}

func (r *Ring) Remove(node string) {
	kept := r.keys[:0]
	for _, h := range r.keys {
		if r.hashMap[h] == node {
			delete(r.hashMap, h)
			continue
		}
		kept = append(kept, h)
	}
	r.keys = kept
}

func (r *Ring) Get(key string) string {
	if len(r.keys) == 0 {
		return ""
	}
	h := hash(key)
	i := sort.Search(len(r.keys), func(i int) bool { return r.keys[i] >= h })
	if i == len(r.keys) {
		i = 0 // wrap around
	}
	return r.hashMap[r.keys[i]]
}

// Demonstration of minimal remapping.
func Demo() (moved, total int) {
	r := New(150)
	r.Add("A")
	r.Add("B")
	r.Add("C")

	before := make(map[string]string)
	for k := 0; k < 1000; k++ {
		key := "key-" + strconv.Itoa(k)
		before[key] = r.Get(key)
	}

	r.Remove("B") // remove one of three nodes

	for key, oldNode := range before {
		if r.Get(key) != oldNode {
			moved++
		}
		total++
	}
	// moved should be ~ 1/3 of total (the keys that were on B),
	// NOT ~all of them as `hash % N` would produce.
	return moved, total
}

