server {
    listen 443 ssl http2;
    server_name api.example.com;

    # TLS terminates here so we can do L7 routing + retries
    ssl_certificate     /etc/nginx/tls/api.crt;
    ssl_certificate_key /etc/nginx/tls/api.key;

    location / {
        proxy_pass https://api_pool;   # re-encrypt on the upstream hop
        proxy_http_version 1.1;
        proxy_set_header Connection "";

        # preserve original client identity past TLS termination
        proxy_set_header Host              $host;
        proxy_set_header X-Real-IP         $remote_addr;
        proxy_set_header X-Forwarded-For   $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # retry an idempotent request on a different backend if one fails
        proxy_next_upstream         error timeout http_502 http_503 http_504;
        proxy_next_upstream_tries   2;
        proxy_next_upstream_timeout 5s;
        proxy_connect_timeout       2s;
        proxy_read_timeout          30s;
    }

    # shallow liveness for the LB / orchestrator
    location = /healthz {
        access_log off;
        return 200 "ok\n";
    }
}

# --- Drain sequence during a rolling deploy (per instance) ---
# 1. Tell instance 10.0.1.13 to begin shutdown; it flips /healthz to 503
#    (or you comment its `server` line and `nginx -s reload`).
# 2. nginx stops sending NEW requests to it (passive/manual removal),
#    but existing in-flight requests on kept-alive conns finish.
# 3. Wait > slowest request (drain timeout) before the process exits.
# 4. Bring up the new instance, confirm /healthz=200, then move to the
#    next instance. Never remove more than spare capacity allows.
